import{_ as a,c as p,a as n,o as r}from"./app-CEcM0piI.js";const t={};function i(s,e){return r(),p("div",null,e[0]||(e[0]=[n(`<h2 id="逻辑语句" tabindex="-1"><a class="header-anchor" href="#逻辑语句"><span>逻辑语句</span></a></h2><h3 id="条件语句" tabindex="-1"><a class="header-anchor" href="#条件语句"><span>条件语句</span></a></h3><p>if……elif……else…… 条件必需为真值才能运行if，若不为真则运行elif，若都不满足则运行else。if语句可以单独存在，elif可以有无数个，if也可以单独与else配合</p><h3 id="for循环语句" tabindex="-1"><a class="header-anchor" href="#for循环语句"><span>for循环语句</span></a></h3><p>for 变量 in 对象:，遍历该范围内包含的所有元素并输出</p><pre><code>- 输出变量得到的结果是遍历的所有元素单个元素在一行，若在后面加，end=‘符号’输出的结果是各个元素在一行排列使用该符号间隔
</code></pre><p>for 对象 in 容器类型: 遍历容器类型的所有元素，输出的对象为该容器中的所有元素。若是字典则输出字典中的所有键</p><h3 id="while循环" tabindex="-1"><a class="header-anchor" href="#while循环"><span>while循环</span></a></h3><p>while 条件： 若满足条件则一直循环，可配合else</p><h3 id="跳出循环" tabindex="-1"><a class="header-anchor" href="#跳出循环"><span>跳出循环</span></a></h3><p>break语句可以跳出for和while的循环体</p><p>continue语句可以跳过当前循环块中的剩余语句，然后继续进行下一轮循环</p><h3 id="空语句" tabindex="-1"><a class="header-anchor" href="#空语句"><span>空语句</span></a></h3><p>pass是空语句，为了保持程序结构的完整性。它被用于那些语法上必须要有什么语句，但程序什么也不做的情况</p><h3 id="创建函数" tabindex="-1"><a class="header-anchor" href="#创建函数"><span>创建函数</span></a></h3><p>def 函数名(参数名，参数名，……)创建自定义函数。定义好后需要调用时函数名(参数，参数，……)小括号里面用于传递参数，定义名和变量定义一样</p><p><strong>可变参数</strong></p><p>*参数 自动收集所有未匹配的位置参数到一个tuple对象中（常见的变量名是args）</p><p>**参数 自动手机所有未匹配的关键字参数到一个dict对象中（常见的变量名是kwargs）调用时传入的参数对应该可变参数位置的参数必须是：参数名=参数 的形式以对应字典类型的键值对</p><p><strong>默认参数</strong></p><p>def 函数名(参数名，参数名=默认参数，参数名=默认参数，……)在定义函数是把默认参数赋值给参数名即可设置默认参数，设置默认参数后，调用该函数时即使不传入参数也会按默认参数运行（默认参数后面必须跟默认参数）</p><p>函数中各种参数排列顺序：函数定义时*args在**kwargs前面。定义参数时按照：普通参数，默认值参数，*参数，**参数 的顺序</p><p>return 函数() 返回函数处理好的结果，python中的函数都有返回值若不使用return之间用变量接收则默认返回none</p><p>lambda 传入参数:函数体(函数代码) 匿名函数用于临时构建一个函数，只能使用一次 函数代码只能写一行 传入参数表示匿名函数的形式参数，如：x，y表示接收2个形式参数</p><p>备注函数 备注的内容，在调用该函数时，光标放在其上会显示备注</p><p>函数遇到return就会结束，因此return放在函数最后</p><p>若一个函数下面有两个return则只执行第一个return，因为return可以退出当前函数，导致下方代码不执行</p><p>让一个函数有多个返回值，使用return 元素,元素。一个return，用逗号元素</p><p>接收时a,b=函数名()。此时a，b分别接收到返回的值</p><h3 id="捕获异常" tabindex="-1"><a class="header-anchor" href="#捕获异常"><span>捕获异常</span></a></h3><ul><li>try：错误的语句</li><li>except：当语句错误时执行的内容</li></ul><p>except(错误类型1，错误类型2)：捕获指定异常 except Exception as e：将错误类型赋值给e，Exception是顶级异常，包含所有异常</p><p>可搭配:</p><ul><li>else：语句没发生错误时执行的内容</li><li>finally：无论是否有异常都执行的内容</li></ul>`,34)]))}const o=a(t,[["render",i]]),l=JSON.parse('{"path":"/python/python/4/","title":"4 逻辑语句","lang":"zh-CN","frontmatter":{"title":"4 逻辑语句","createTime":"2025/04/05 12:12:26","permalink":"/python/python/4/"},"readingTime":{"minutes":3.21,"words":962},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/Python/python/4 逻辑语句.md","headers":[]}');export{o as comp,l as data};
